namespace BlazorApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Hydraulic Press #4", "Building A - Floor 2", new DateTime(2026, 4, 10)),
            new(2, "CNC Lathe M200", "Building B - Shop 1", new DateTime(2026, 5, 1)),
            new(3, "Forklift FL-12", "Warehouse C", new DateTime(2026, 3, 22)),
            new(4, "Conveyor Belt Section 7", "Building A - Floor 1", new DateTime(2026, 5, 15)),
            new(5, "Arc Welder W900", "Building B - Shop 3", new DateTime(2026, 2, 28)),
            new(6, "Compressor Unit #2", "Utility Room", new DateTime(2026, 4, 30)),
            new(7, "Overhead Crane OC-5", "Building A - Floor 2", new DateTime(2026, 1, 14)),
            new(8, "Band Saw BS-300", "Building B - Shop 1", new DateTime(2026, 5, 18)),
        };
    }
}

@page "/inventory"
@attribute [StreamRendering]
@rendermode InteractiveServer
@using BlazorApp.Services
@inject IEquipmentService EquipmentService

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;

    protected override async Task OnInitializedAsync()
    {
        items = await EquipmentService.GetEquipmentAsync();
    }
}

